body:
Hi, does torder support hierarchical designs or does it require flat design?
Design below will give loop if hierarchical and if flattened no loop.

```
design -reset; read_verilog -defer ./torder_test.v
hierarchy -top torder_test; prep; opt; clean -purge; torder
```

```
module torder_test (i_in, d_out, clk, rst);
   input i_in, clk, rst;
   output d_out; 

   wire   out_q;

   sub_module u0 (
      .in_b ((out_q & i_in)),
      .out (out_q),
      .clk (clk),
      .rst (rst)
      );
   
   assign d_out = out_q;

endmodule

module sub_module (clk, rst, in_b, out);   
   
   input clk, rst, in_b;     
   output out;   
   reg    out;   

   always @(posedge clk) begin
      if (rst) begin
         out <= 0;
      end
      else begin
         out <= in_b;
      end
   end 

endmodule 
```

